import type { Metadata } from "next"
import { ConferenceBooking } from "./ConferenceBooking"

export const metadata: Metadata = {
    title: "三者面談 予約スケジュール | @gunjo/ui 評価",
    description:
        "保護者面談（三者面談）の予約枠グリッド・予約状況・未予約フォローを @gunjo/ui で構築した画面。",
}

export default function ConferenceBookingPage() {
    return <ConferenceBooking />
}

/**
 * Seed data for the 三者面談予約 (parent–teacher conference booking) screen.
 *
 * Built cold against @gunjo/ui@0.0.1-alpha.2. The slot grid is modelled on the
 * ScheduleGrid axis/cell shape (rows = time-slots, columns = days) so the data
 * maps 1:1 onto `ScheduleAxisItem` / `ScheduleCell`.
 */

export type SlotStatus = "available" | "booked" | "blocked"

/** A family (= one student's household) in the homeroom class. */
export interface Family {
    id: string
    studentName: string
    /** ふりがな for sorting / aria. */
    studentKana: string
    guardianName: string
    /** Used only to show who to chase; not a real contact integration. */
    phone: string
}

/** A bookable time-slot on a given day. */
export interface Slot {
    id: string
    dayId: string
    startId: string // row id
    /** "16:00" */
    start: string
    /** "16:20" */
    end: string
    status: SlotStatus
    /** familyId when status === "booked". */
    familyId?: string
    /** Reason shown for a blocked slot, e.g. "職員会議". */
    blockedReason?: string
    /** 相談内容 / メモ attached at booking time. */
    note?: string
}

export interface Day {
    id: string
    /** "12/15" */
    label: string
    /** "月" */
    weekday: string
    /** ISO-ish for aria / sorting. */
    date: string
}

export interface TimeRow {
    id: string
    start: string
    end: string
}

export const CLASS_LABEL = "3年2組"
export const TEACHER_NAME = "田中 美咲"

export const families: Family[] = [
    { id: "f01", studentName: "青木 陽翔", studentKana: "あおき はると", guardianName: "青木 健一", phone: "090-1111-0001" },
    { id: "f02", studentName: "石田 美月", studentKana: "いしだ みづき", guardianName: "石田 由美", phone: "090-1111-0002" },
    { id: "f03", studentName: "上野 蓮", studentKana: "うえの れん", guardianName: "上野 直樹", phone: "090-1111-0003" },
    { id: "f04", studentName: "遠藤 さくら", studentKana: "えんどう さくら", guardianName: "遠藤 京子", phone: "090-1111-0004" },
    { id: "f05", studentName: "小川 大和", studentKana: "おがわ やまと", guardianName: "小川 浩二", phone: "090-1111-0005" },
    { id: "f06", studentName: "加藤 結愛", studentKana: "かとう ゆあ", guardianName: "加藤 真理", phone: "090-1111-0006" },
    { id: "f07", studentName: "木村 颯太", studentKana: "きむら そうた", guardianName: "木村 拓也", phone: "090-1111-0007" },
    { id: "f08", studentName: "工藤 凛", studentKana: "くどう りん", guardianName: "工藤 香織", phone: "090-1111-0008" },
    { id: "f09", studentName: "小林 悠真", studentKana: "こばやし ゆうま", guardianName: "小林 誠", phone: "090-1111-0009" },
    { id: "f10", studentName: "佐藤 葵", studentKana: "さとう あおい", guardianName: "佐藤 智子", phone: "090-1111-0010" },
    { id: "f11", studentName: "鈴木 陽菜", studentKana: "すずき ひな", guardianName: "鈴木 一郎", phone: "090-1111-0011" },
    { id: "f12", studentName: "高橋 樹", studentKana: "たかはし いつき", guardianName: "高橋 美奈", phone: "090-1111-0012" },
]

export const days: Day[] = [
    { id: "d1", label: "12/15", weekday: "月", date: "2025-12-15" },
    { id: "d2", label: "12/16", weekday: "火", date: "2025-12-16" },
    { id: "d3", label: "12/17", weekday: "水", date: "2025-12-17" },
    { id: "d4", label: "12/18", weekday: "木", date: "2025-12-18" },
]

export const timeRows: TimeRow[] = [
    { id: "t1", start: "16:00", end: "16:20" },
    { id: "t2", start: "16:20", end: "16:40" },
    { id: "t3", start: "16:40", end: "17:00" },
    { id: "t4", start: "17:00", end: "17:20" },
    { id: "t5", start: "17:20", end: "17:40" },
    { id: "t6", start: "17:40", end: "18:00" },
]

/**
 * Build the initial slot matrix: 4 days × 6 time-rows = 24 slots, with a
 * realistic mix of available / booked / blocked.
 */
function buildSlots(): Slot[] {
    const slots: Slot[] = []
    for (const day of days) {
        for (const row of timeRows) {
            slots.push({
                id: `${day.id}-${row.id}`,
                dayId: day.id,
                startId: row.id,
                start: row.start,
                end: row.end,
                status: "available",
            })
        }
    }

    const set = (
        dayId: string,
        startId: string,
        patch: Partial<Slot>
    ) => {
        const s = slots.find((x) => x.dayId === dayId && x.startId === startId)
        if (s) Object.assign(s, patch)
    }

    // Day 1 (月)
    set("d1", "t1", { status: "booked", familyId: "f01", note: "進路（私立か公立か）について相談したい" })
    set("d1", "t2", { status: "booked", familyId: "f02", note: "家庭学習の習慣づけ" })
    set("d1", "t4", { status: "blocked", blockedReason: "職員会議" })
    set("d1", "t5", { status: "blocked", blockedReason: "職員会議" })
    set("d1", "t6", { status: "booked", familyId: "f03" })

    // Day 2 (火)
    set("d2", "t1", { status: "booked", familyId: "f05", note: "部活と勉強の両立" })
    set("d2", "t3", { status: "booked", familyId: "f06" })
    set("d2", "t4", { status: "booked", familyId: "f07", note: "欠席が増えている件" })

    // Day 3 (水) — teacher out for a training in the late afternoon
    set("d3", "t1", { status: "booked", familyId: "f09" })
    set("d3", "t5", { status: "blocked", blockedReason: "教員不在（研修）" })
    set("d3", "t6", { status: "blocked", blockedReason: "教員不在（研修）" })

    // Day 4 (木)
    set("d4", "t2", { status: "booked", familyId: "f10", note: "受験校の最終確認" })
    set("d4", "t3", { status: "booked", familyId: "f12" })

    return slots
}

export const initialSlots: Slot[] = buildSlots()

"use client"

/**
 * SlotSheet — the book / change / cancel interaction for a single time-slot.
 *
 * Opened by clicking a cell in the ScheduleGrid. Built from @gunjo/ui's
 * Sheet (right drawer) + Select + Button + Alert + Badge + Textarea.
 *
 * Double-booking prevention lives here and in the parent:
 *  - The family <Select> excludes families that already hold ANOTHER slot
 *    (`bookedFamilyIds`), so you physically can't pick someone who's booked.
 *  - The slot itself is single-cell, so it can only ever hold one family.
 *  - The parent re-checks on confirm (live re-check) before committing.
 */

import * as React from "react"
import {
    IconAlertTriangle,
    IconCalendarEvent,
    IconTrash,
} from "@tabler/icons-react"
import {
    Alert,
    AlertDescription,
    AlertTitle,
    Badge,
    Button,
    Select,
    Sheet,
    SheetClose,
    SheetContent,
    SheetDescription,
    SheetFooter,
    SheetHeader,
    SheetTitle,
    Textarea,
} from "@gunjo/ui"

import type { Family, Slot } from "./data"

export interface SlotSheetProps {
    open: boolean
    onOpenChange: (open: boolean) => void
    slot: Slot | null
    families: Family[]
    /** Family ids currently holding ANY slot — used to prevent double-booking. */
    bookedFamilyIds: Set<string>
    dayLabel: string
    onBook: (slotId: string, familyId: string, note: string) => void
    onCancel: (slotId: string) => void
    onBlockToggle: (slotId: string, reason: string) => void
}

export function SlotSheet({
    open,
    onOpenChange,
    slot,
    families,
    bookedFamilyIds,
    dayLabel,
    onBook,
    onCancel,
    onBlockToggle,
}: SlotSheetProps) {
    const [familyId, setFamilyId] = React.useState<string>("")
    const [note, setNote] = React.useState<string>("")
    const [error, setError] = React.useState<string | null>(null)

    // Reset local form whenever a new slot is opened.
    React.useEffect(() => {
        if (slot) {
            setFamilyId(slot.familyId ?? "")
            setNote(slot.note ?? "")
            setError(null)
        }
    }, [slot])

    if (!slot) return null

    const current = slot.familyId
        ? families.find((f) => f.id === slot.familyId)
        : undefined

    // Families that may be assigned to THIS slot: not booked elsewhere, OR the
    // family already on this slot (so you can keep it when only editing the note).
    const selectableFamilies = families.filter(
        (f) => !bookedFamilyIds.has(f.id) || f.id === slot.familyId
    )

    const timeText = `${slot.start}–${slot.end}`

    const handleConfirm = () => {
        if (!familyId) {
            setError("家庭を選択してください。")
            return
        }
        // Live re-check: someone may have grabbed this family in another tab/slot.
        if (bookedFamilyIds.has(familyId) && familyId !== slot.familyId) {
            setError("この家庭は既に別の枠を予約しています。1家庭につき1枠までです。")
            return
        }
        onBook(slot.id, familyId, note.trim())
        onOpenChange(false)
    }

    return (
        <Sheet open={open} onOpenChange={onOpenChange}>
            <SheetContent
                side="right"
                className="flex w-full flex-col gap-0 overflow-y-auto sm:max-w-md"
                aria-describedby={undefined}
            >
                <SheetHeader>
                    <div className="flex items-center gap-2">
                        <IconCalendarEvent className="h-5 w-5 text-muted-foreground" aria-hidden />
                        <SheetTitle>面談枠の予約</SheetTitle>
                    </div>
                    <SheetDescription>
                        {dayLabel}（{slot.start}–{slot.end}）の枠を予約・変更・取消します。
                    </SheetDescription>
                </SheetHeader>

                <div className="flex flex-1 flex-col gap-5 py-6">
                    {/* Slot identity */}
                    <div className="flex items-center justify-between rounded-lg border border-border bg-muted/30 px-3 py-2.5">
                        <div className="flex flex-col">
                            <span className="text-xs text-muted-foreground">{dayLabel}</span>
                            <span className="text-base font-semibold tabular-nums">{timeText}</span>
                        </div>
                        {slot.status === "booked" ? (
                            <Badge variant="success">予約済</Badge>
                        ) : slot.status === "blocked" ? (
                            <Badge variant="warning">受付不可</Badge>
                        ) : (
                            <Badge variant="info">空き</Badge>
                        )}
                    </div>

                    {slot.status === "blocked" ? (
                        <>
                            <Alert variant="warning">
                                <IconAlertTriangle className="h-4 w-4" aria-hidden />
                                <AlertTitle as="h3">この枠は受付停止中です</AlertTitle>
                                <AlertDescription>
                                    理由: {slot.blockedReason ?? "（未設定）"}。受付を再開すると家庭が予約できるようになります。
                                </AlertDescription>
                            </Alert>
                            <Button
                                variant="outline"
                                onClick={() => {
                                    onBlockToggle(slot.id, "")
                                    onOpenChange(false)
                                }}
                            >
                                受付を再開する（空きに戻す）
                            </Button>
                        </>
                    ) : (
                        <>
                            {current ? (
                                <div className="rounded-lg border border-success-border bg-success-subtle px-3 py-2.5 text-sm text-success-subtle-foreground">
                                    現在の予約: <span className="font-semibold">{current.studentName}</span>（保護者: {current.guardianName}）
                                </div>
                            ) : null}

                            <Select
                                label="予約する家庭"
                                description="既に別の枠を予約済みの家庭は一覧に表示されません（1家庭1枠）。"
                                value={familyId}
                                onChange={(e) => {
                                    setFamilyId(e.target.value)
                                    setError(null)
                                }}
                            >
                                <option value="">家庭を選択…</option>
                                {selectableFamilies.map((f) => (
                                    <option key={f.id} value={f.id}>
                                        {f.studentName}（{f.guardianName}）
                                    </option>
                                ))}
                            </Select>

                            <div className="flex flex-col gap-1.5">
                                <label
                                    htmlFor="slot-note"
                                    className="text-sm font-medium leading-none text-foreground"
                                >
                                    相談内容・メモ（任意）
                                </label>
                                <Textarea
                                    id="slot-note"
                                    rows={3}
                                    placeholder="例: 進路について / 家庭学習の様子 など"
                                    value={note}
                                    onChange={(e) => setNote(e.target.value)}
                                />
                            </div>

                            {error ? (
                                <Alert variant="destructive" role="alert">
                                    <IconAlertTriangle className="h-4 w-4" aria-hidden />
                                    <AlertTitle as="h3">予約できません</AlertTitle>
                                    <AlertDescription>{error}</AlertDescription>
                                </Alert>
                            ) : null}
                        </>
                    )}
                </div>

                {slot.status !== "blocked" ? (
                    <SheetFooter className="flex-col gap-2 sm:flex-col sm:gap-2">
                        <Button onClick={handleConfirm} className="w-full">
                            {slot.status === "booked" ? "予約を更新する" : "この枠を予約する"}
                        </Button>
                        <div className="flex w-full gap-2">
                            {slot.status === "booked" ? (
                                <Button
                                    variant="destructive"
                                    className="flex-1"
                                    onClick={() => {
                                        onCancel(slot.id)
                                        onOpenChange(false)
                                    }}
                                >
                                    <IconTrash className="h-4 w-4" aria-hidden />
                                    予約を取消
                                </Button>
                            ) : (
                                <Button
                                    variant="outline"
                                    className="flex-1"
                                    onClick={() => {
                                        onBlockToggle(slot.id, "教員不在")
                                        onOpenChange(false)
                                    }}
                                >
                                    受付不可にする
                                </Button>
                            )}
                            <SheetClose asChild>
                                <Button variant="ghost" className="flex-1">
                                    閉じる
                                </Button>
                            </SheetClose>
                        </div>
                    </SheetFooter>
                ) : null}
            </SheetContent>
        </Sheet>
    )
}
